def test_creator_commit_visual_qa_auto_ingests_report_metadata_only(monkeypatch, tmp_path):
    monkeypatch.setenv("CAPY_MEMORY_TREE_ROOT", str(tmp_path / "capy-memory"))
    spaces = _load_spaces(monkeypatch, tmp_path, enabled=True)
    import api.capy_memory as capy_memory

    preview = spaces.run_space_tool(
        "space.creator.preview",
        {
            "prompt": "Build a safe visual QA status card.",
            "spaceName": "Visual QA Memory Lab",
            "widgets": [
                {
                    "widgetId": "qa-status",
                    "title": "QA Status",
                    "kind": "status",
                    "renderer": "<script>bad()</script>",
                    "api_key": "SECRET_VALUE_DO_NOT_LEAK",
                }
            ],
        },
    )
    commit = spaces.run_space_tool(
        "space.creator.commit",
        {
            "preview_id": preview["preview_id"],
            "sandbox_previewed": True,
            "visual_qa_passed": True,
            "approve_commit": True,
            "screenshot_path": "/private/tmp/SECRET_VALUE_DO_NOT_LEAK/visual-qa.png",
        },
    )

    relevant = capy_memory.relevant_memory_for_space(commit["space_id"], limit=20)
    visual_hits = [row for row in relevant["results"] if row["source_type"] == "visual_qa_report"]
    serialized = json.dumps(visual_hits, sort_keys=True).lower()

    assert commit["ok"] is True
    assert commit["visual_qa_event"]["event_type"] == "space.visual_qa.completed"
    assert visual_hits
    assert "creator commit visual qa" in serialized
    assert "passed" in serialized
    assert "visual-qa.png" in serialized
    assert "/private/tmp" not in serialized
    assert "raw prompt" not in serialized
    assert "secret_value_do_not_leak" not in serialized
    assert "<script" not in serialized
    assert "api_key" not in serialized
    assert "renderer" not in serialized



def test_space_checkpoint_tool_creates_metadata_only_revision_anchor(monkeypatch, tmp_path):
    spaces = _load_spaces(monkeypatch, tmp_path, enabled=True)
    created = spaces.create_space({"space_id": "checkpoint-lab", "name": "Checkpoint Lab"})
    before_revisions = list(created.get("revision_events") or [])

    result = spaces.run_space_tool(
        "space.checkpoint",
        {
            "spaceId": created["space_id"],
            "reason": "before rollback renderer <script>bad()</script> api_key SECRET_VALUE_DO_NOT_LEAK",
        },
    )

    assert result["ok"] is True
    assert result["action"] == "space.checkpoint"
    assert result["space_id"] == created["space_id"]
    assert result["event_type"] == "space.checkpointed"
    assert result["metadata_only"] is True
    assert result["generated_widgets_rendered"] is False
    assert result["revision_event_id"]
    assert result["revision_event_id"] not in before_revisions
    assert result["prompt_preflight"]["boundary"] == "recovery_action"
    assert result["prompt_preflight"]["status"] == "required"
    assert result["prompt_preflight"]["metadata_only"] is True
    assert result["prompt_preflight"]["raw_prompt_stored"] is False
    assert result["autonomy_policy"]["action"] == "space.checkpoint"
    assert result["autonomy_policy"]["metadata_only"] is True
    assert result["autonomy_policy"]["approval_gates"] == ["creator_commit", "generated_widget_execution"]
    assert result["autonomy_policy"]["prompt_preflight_status"] == result["prompt_preflight"]["status"]
    assert result["autonomy_policy"]["model_route_hint"] == "hint:reasoning"
    assert result["progress_event"]["event_type"] == "tool.completed"
    assert result["progress_event"]["family"] == "tool"
    assert result["progress_event"]["run_id"] == f"checkpoint:{created['space_id']}"
    assert result["progress_event"]["space_id"] == created["space_id"]
    assert result["progress_event"]["redaction_status"] == "metadata_only"
    _assert_server_memory_advisory_receipt(result)
    compaction = result["output_compaction"]
    assert compaction["tool"] == "capy-spaces-tool-action"
    assert compaction["command"] == "space.checkpoint"
    assert compaction["metadata_only"] is True
    assert compaction["redaction_status"] == "metadata_only"
    assert compaction["original_chars"] > 0
    assert compaction["compacted_chars"] > 0
    assert "space_action: space.checkpoint" in compaction["text"]
    assert "widget_count" not in compaction["text"]
    assert f"progress_run_id: checkpoint:{created['space_id']}" in compaction["text"]
    handles = compaction["retained_artifact_handles"]
    assert {"kind": "space", "handle": f"space:{created['space_id']}", "label": "Space action metadata"} in handles
    assert any(handle.get("handle") == f"revision:{result['revision_event_id']}" for handle in handles)
    serialized_compaction = json.dumps(compaction, sort_keys=True).lower()
    assert "renderer" not in serialized_compaction
    assert "<script" not in serialized_compaction
    assert "api_key" not in serialized_compaction
    assert "secret_value_do_not_leak" not in serialized_compaction

    loaded = spaces._read_space_manifest(created["space_id"])
    assert loaded["revision_event_id"] == result["revision_event_id"]
    assert loaded["revision_events"] == before_revisions + [result["revision_event_id"]]

    event_path = spaces.events_dir() / f"{result['revision_event_id']}.json"
    event = json.loads(event_path.read_text(encoding="utf-8"))
    details = event["details"]
    assert event["event_type"] == "space.checkpointed"
    assert event["space_id"] == created["space_id"]
    assert details["metadata_only"] is True
    assert details["generated_widgets_rendered"] is False
    assert details["reason"] == "[REDACTED]"
    serialized_details = json.dumps(details, sort_keys=True).lower()
    assert "renderer" not in serialized_details
    assert "<script" not in serialized_details
    assert "api_key" not in serialized_details
    assert "secret_value_do_not_leak" not in serialized_details



