    spaces.set_shared_data_slot(
        created["space_id"],
        "research_notes",
        {"summary": "Safe notes", "api_key": "SECRET_VALUE_DO_NOT_LEAK"},
        {"source_widget": "old-panel", "token": "TOKEN_VALUE"},
    )
