def test_space_tool_adapter_exposes_metadata_only_current_context(monkeypatch, tmp_path):
    spaces = _load_spaces(monkeypatch, tmp_path, enabled=True)
    created = spaces.create_space(
        {
            "space_id": "context-lab",
            "name": "Context Lab",
            "description": "Agent prompt context bridge",
            "agent_instructions": "Patch widgets through typed APIs only.",
        }
    )
    spaces.upsert_widget(
        created["space_id"],
        {
            "id": "research-summary",
            "kind": "markdown",
            "title": "Summary",
            "renderer": "<script>steal()</script>",
            "data": {"api_key": "***"},
        },
    )
    queued = spaces.queue_widget_event(
        created["space_id"],
        "research-summary",
        "agent.prompt",
        {"api_key": "SECRET_VALUE_DO_NOT_LEAK", "renderer": "<script>bad()</script>"},
        prompt="Investigate the safe widget summary.",
        session_id="webui-session-123",
    )

    result = spaces.run_space_tool("space.current.context", {"active_space_id": created["space_id"]})
    no_current = spaces.run_space_tool("space.current.context", {})
    from api.capy_progress import progress_status

    scoped_progress = progress_status(space_id=created["space_id"])
    serialized = json.dumps({"result": result, "no_current": no_current}, sort_keys=True).lower()

    assert result["ok"] is True
    assert result["action"] == "space.current.context"
    assert result["active_space_id"] == created["space_id"]
    assert result["context"].startswith("## Active Capy Space")
    assert "id: context-lab" in result["context"]
    assert "research-summary|Summary|markdown" in result["context"]
    assert "Patch widgets through typed APIs only." in result["context"]
    assert "queued widget events (event_id|widget_id|event_name|status):" in result["context"]
    assert f"{queued['event_id']}|research-summary|agent.prompt|queued" in result["context"]
    compaction = result["output_compaction"]
    assert compaction["tool"] == "capy-spaces-context"
    assert compaction["command"] == "space.current.context"
    assert compaction["exit_status"] == 0
    assert compaction["redaction_status"] in {"none", "redacted"}
    assert compaction["compacted_chars"] > 0
    assert "## Active Capy Space" in compaction["text"]
    _assert_server_memory_advisory_receipt(result)
    assert result["context_status"]["metadata_only"] is True
    assert result["context_status"]["local_only"] is True
    assert {"memory", "policy", "progress"}.issubset(result["context_status"])
    assert result["prompt_preflight"]["boundary"] == "memory_context"
    assert result["prompt_preflight"]["status"] == "pass"
    assert result["prompt_preflight"]["metadata_only"] is True
    assert result["prompt_preflight"]["raw_prompt_stored"] is False
    assert result["autonomy_policy"]["action"] == "space.current.context"
    assert result["autonomy_policy"]["prompt_preflight_status"] == "pass"
    assert result["autonomy_policy"]["approval_gates"] == ["creator_commit", "generated_widget_execution"]
    assert result["autonomy_policy"]["metadata_only"] is True
    progress_event = result["progress_event"]
    assert progress_event["stored"] is True
    assert progress_event["queued"] is True
    assert progress_event["event_type"] == "tool.completed"
    assert progress_event["family"] == "tool"
    assert progress_event["run_id"] == "context:context-lab"
    assert progress_event["space_id"] == created["space_id"]
    assert progress_event["redaction_status"] == "metadata_only"
    assert scoped_progress["space_id"] == created["space_id"]
    assert scoped_progress["recent_family_counts"]["tool"] >= 2
    assert scoped_progress["recent_events"][0]["run_id"] == "context:context-lab"
    assert scoped_progress["recent_events"][0]["event_type"] == "tool.completed"
    assert no_current["ok"] is True
    assert no_current["action"] == "space.current.context"
    assert no_current["active_space_id"] is None
    assert no_current["context"] == ""
    assert no_current["output_compaction"]["tool"] == "capy-spaces-context"
    assert no_current["output_compaction"]["command"] == "space.current.context"
    assert no_current["output_compaction"]["metadata_only"] is True
    # The no-current fallback has no context body, but still compacts the
    # metadata-only server memory advisory receipt documented below.
    assert no_current["output_compaction"]["original_chars"] > 0
    assert no_current["output_compaction"]["compacted_chars"] > 0
    _assert_server_memory_advisory_receipt(no_current)
    assert no_current["prompt_preflight"]["boundary"] == "memory_context"
    assert no_current["prompt_preflight"]["status"] == "required"
    assert no_current["prompt_preflight"]["metadata_only"] is True
    assert no_current["prompt_preflight"]["raw_prompt_stored"] is False
    assert no_current["autonomy_policy"]["action"] == "space.current.context"
    assert no_current["autonomy_policy"]["prompt_preflight_status"] == "required"
    assert no_current["autonomy_policy"]["approval_gates"] == ["creator_commit", "generated_widget_execution"]
    assert no_current["progress_event"]["event_type"] == "tool.completed"
    assert no_current["progress_event"]["run_id"] == "context:none"
    assert no_current["progress_event"]["redaction_status"] == "metadata_only"
    assert no_current["progress_event"]["metadata_only"] is True
    assert "space_id" not in no_current["progress_event"]
    assert "prompt_preflight_status: required" in no_current["output_compaction"]["text"]
    assert "autonomy_action: space.current.context" in no_current["output_compaction"]["text"]
    assert "progress_run_id: context:none" in no_current["output_compaction"]["text"]
    assert "space_id:" not in no_current["output_compaction"]["text"]
    assert no_current["context_status"]["metadata_only"] is True
    assert "investigate secret_value_do_not_leak" not in serialized
    assert "steal" not in serialized
    assert "<script" not in serialized
    assert "renderer" not in serialized
    assert "api_key" not in serialized
    assert "unsafe_marker_do_not_leak" not in serialized


