def test_space_tool_adapter_lists_and_restores_revisions_metadata_only(monkeypatch, tmp_path):
    spaces = _load_spaces(monkeypatch, tmp_path, enabled=True)
    created = spaces.create_space({"space_id": "tool-rollback", "name": "Tool Rollback"})
    original_event_id = created["revision_event_id"]
    spaces.upsert_widget(
        created["space_id"],
        {
            "id": "unsafe-card",
            "kind": "html",
            "title": "Unsafe Card",
            "renderer": "<script>steal()</script>",
            "data": {"api_key": "SECRET_VALUE_DO_NOT_LEAK"},
        },
    )
    spaces.update_space(created["space_id"], {"description": "Updated for restore"})

    listed = spaces.run_space_tool("space.revisions", {"space_id": created["space_id"], "limit": 5})
    restored = spaces.run_space_tool(
        "space.revision.restore",
        {"space_id": created["space_id"], "event_id": original_event_id, "renderer": "<script>ignore()</script>"},
    )
    serialized = json.dumps({"listed": listed, "restored": restored}).lower()

    assert listed["ok"] is True
    assert listed["action"] == "space.revisions"
    assert [event["event_type"] for event in listed["revisions"]][:3] == [
        "space.updated",
        "widget.created",
        "space.created",
    ]
    assert restored["ok"] is True
    assert restored["action"] == "space.revision.restore"
    assert restored["restored_event_id"] == original_event_id
    assert restored["space"]["space_id"] == created["space_id"]
    assert restored["space"]["widgets"] == []
    assert restored["prompt_preflight"]["available"] is True
    assert restored["prompt_preflight"]["action"] == "space.recovery.restore"
    assert restored["prompt_preflight"]["boundary"] == "recovery_action"
    assert restored["prompt_preflight"]["status"] == "required"
    assert restored["prompt_preflight"]["metadata_only"] is True
    assert restored["prompt_preflight"]["raw_prompt_stored"] is False
    assert restored["autonomy_policy"]["action"] == "space.recovery.restore"
    assert restored["autonomy_policy"]["approval_gates"] == ["creator_commit", "generated_widget_execution"]
    assert restored["autonomy_policy"]["prompt_preflight_status"] == "required"
    assert restored["autonomy_policy"]["model_route_hint"] == "hint:reasoning"
    assert restored["autonomy_policy"]["metadata_only"] is True
    assert restored["progress_event"]["stored"] is True
    assert restored["progress_event"]["queued"] is True
    assert restored["progress_event"]["event_type"] == "tool.completed"
    assert restored["progress_event"]["family"] == "tool"
    assert restored["progress_event"]["run_id"] == "recovery.restore:tool-rollback"
    assert restored["progress_event"]["space_id"] == created["space_id"]
    assert restored["progress_event"]["redaction_status"] == "metadata_only"
    compaction = restored["output_compaction"]
    assert compaction["metadata_only"] is True
    assert compaction["tool"] == "capy-spaces-tool-action"
    assert compaction["command"] == "space.recovery.restore"
    assert compaction["exit_status"] == 0
    assert "retain_artifact_handles" in compaction["rules_applied"]
    assert f"space_id: {created['space_id']}" in compaction["text"]
    assert original_event_id in compaction["text"]
    assert restored["revision_event_id"] in compaction["text"]
    assert "prompt_preflight_status: required" in compaction["text"]
    assert "model_route_hint: hint:reasoning" in compaction["text"]
    assert "progress_run_id: recovery.restore:tool-rollback" in compaction["text"]
    _assert_server_memory_advisory_receipt(restored)
    from api.capy_progress import progress_status

    status = progress_status(space_id=created["space_id"])
    recent_run_ids = [event["run_id"] for event in status["recent_events"]]
    assert "recovery.restore:tool-rollback" in recent_run_ids
    assert "steal" not in serialized
    assert "<script" not in serialized
    assert "renderer" not in serialized
    assert "api_key" not in serialized
    assert "secret" not in serialized
    assert "secret_value_do_not_leak" not in serialized


