def test_space_tool_adapter_admin_rollback_aliases_restore_metadata_only(monkeypatch, tmp_path):
    spaces = _load_spaces(monkeypatch, tmp_path, enabled=True)
    aliases = (
        "space.admin.rollback",
        "space.admin.restore",
        "space.admin.revision.restore",
        "space.admin.recovery.rollback",
        "space.admin.recovery.restore",
    )

    for index, alias in enumerate(aliases):
        created = spaces.create_space({"space_id": f"tool-admin-rollback-{index}", "name": "Admin Rollback"})
        original_event_id = created["revision_event_id"]
        spaces.upsert_widget(
            created["space_id"],
            {
                "id": "bad-widget",
                "kind": "html",
                "title": "Broken Widget",
                "renderer": "<script>breakAdminRecovery()</script>",
                "source": "raw generated source should stay private",
                "data": {"api_key": "SECRET_VALUE_DO_NOT_LEAK"},
            },
        )
        spaces.disable_space_for_recovery(created["space_id"], reason="generated shell failed")

        restored = spaces.run_space_tool(
            alias,
            {
                "spaceId": created["space_id"],
                "eventId": original_event_id,
                "renderer": "<script>ignore()</script>",
                "api_key": "SECRET_VALUE_DO_NOT_LEAK",
            },
        )
        serialized = json.dumps(restored).lower()

        assert restored["ok"] is True
        assert restored["action"] == alias
        assert restored["space"]["space_id"] == created["space_id"]
        assert restored["restored_event_id"] == original_event_id
        assert restored["revision_event_id"]
        assert restored["space"]["widgets"] == []
        assert "active_space_id" not in restored
        assert "renderer" not in serialized
        assert "source" not in serialized
        assert "api_key" not in serialized
        assert "secret_value_do_not_leak" not in serialized
        assert "<script" not in serialized


def test_space_tool_adapter_admin_rollback_rejects_conflicting_space_aliases_before_side_effects(monkeypatch, tmp_path):
    spaces = _load_spaces(monkeypatch, tmp_path, enabled=True)
    target = spaces.create_space({"space_id": "tool-admin-space-conflict-target", "name": "Target Original"})
    other = spaces.create_space({"space_id": "tool-admin-space-conflict-other", "name": "Other Original"})
    target_original_event_id = target["revision_event_id"]
    target_updated = spaces.update_space(target["space_id"], {"name": "Target Patched"})
    other_updated = spaces.update_space(other["space_id"], {"name": "Other Patched"})

    with pytest.raises(ValueError, match="space selector aliases"):
        spaces.run_space_tool(
            "space.admin.rollback",
            {
                "space_id": target["space_id"],
                "spaceId": other["space_id"],
                "eventId": target_original_event_id,
                "renderer": "<script>should-not-leak()</script>",
                "api_key": "SECRET_VALUE_DO_NOT_LEAK",
            },
        )

    target_detail = spaces.read_space_detail(target["space_id"])
    other_detail = spaces.read_space_detail(other["space_id"])
    serialized = json.dumps({"target": target_detail, "other": other_detail}).lower()
    assert target_detail["name"] == "Target Patched"
    assert target_detail["revision_event_id"] == target_updated["revision_event_id"]
    assert other_detail["name"] == "Other Patched"
    assert other_detail["revision_event_id"] == other_updated["revision_event_id"]
    assert "renderer" not in serialized
    assert "api_key" not in serialized
    assert "secret_value_do_not_leak" not in serialized
    assert "<script" not in serialized


def test_space_tool_adapter_admin_rollback_rejects_conflicting_event_aliases_before_side_effects(monkeypatch, tmp_path):
    spaces = _load_spaces(monkeypatch, tmp_path, enabled=True)
    created = spaces.create_space({"space_id": "tool-admin-rollback-conflict", "name": "Original"})
    original_event_id = created["revision_event_id"]
    updated = spaces.update_space(created["space_id"], {"name": "Patched"})
    patched_event_id = updated["revision_event_id"]

    conflicting_payloads = (
        {
            "spaceId": created["space_id"],
            "event_id": original_event_id,
            "revisionEventId": patched_event_id,
        },
        {
            "spaceId": created["space_id"],
            "eventId": patched_event_id,
            "args": [created["space_id"], original_event_id],
        },
    )

    for payload in conflicting_payloads:
        with pytest.raises(ValueError, match="selector aliases"):
            spaces.run_space_tool(
                "space.admin.rollback",
                {
                    **payload,
                    "renderer": "<script>should-not-leak()</script>",
                    "api_key": "SECRET_VALUE_DO_NOT_LEAK",
                },
            )

    detail = spaces.read_space_detail(created["space_id"])
    serialized = json.dumps(detail).lower()
    assert detail["name"] == "Patched"
    assert detail["revision_event_id"] == patched_event_id
    assert "renderer" not in serialized
    assert "api_key" not in serialized
    assert "secret_value_do_not_leak" not in serialized
    assert "<script" not in serialized


